dashboard.definition:
{
  "title": "Native Single-Value Benchmark \u2014 250 panels",
  "description": "250 native splunk.singlevalue panels using a shared ds.test source. For benchmarking custom-viz iframe cost vs native panel mount cost.",
  "dataSources": {
    "ds_shared": {
      "type": "ds.test",
      "options": {
        "data": {
          "fields": [
            {
              "name": "value"
            }
          ],
          "columns": [
            [
              "42"
            ]
          ]
        }
      },
      "name": "Shared stub \u2014 value=42"
    }
  },
  "defaults": {},
  "visualizations": {
    "viz_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "# Native Single-Value Benchmark \u2014 250 panels\nEach panel is a `splunk.singlevalue` reading the same `ds.test` stub data source. Use this to compare cold-load time against the `250`-panel icon_library showcase. Hard-reload the page to measure first paint; watch the bottom-bar Finish timer in DevTools Network for the wall-clock load time.",
        "fontColor": "#E2E8F0",
        "backgroundColor": "transparent"
      }
    },
    "viz_sv_000": {
      "type": "splunk.singlevalue",
      "dataSources": {
        "primary": "ds_shared"
